/**
 * 新增 subject event。
 */
export default defineEventHandler((event) => withProjectNotOpenHttpError(async () => {
    const body = await validateBody(event, ProjectRagEventWriteRequestDtoSchema);
    const result = await createProjectRagEvent(runtimePathsFromEnv().workspaceRoot, requireProjectPathQuery(event), body);
    return ProjectRagSubjectDtoSchema.parse(result);
}));
